    #[test]
    fn start_resets_turn_counters() {
        let mut tracker = TokenRateTracker::new();
        tracker.start();
        tracker.record(35); // simulate a token
        tracker.start(); // reset
        // After reset, is_streaming is true but cumulative_chars is 0
        assert!(tracker.is_streaming());
    }

    #[test]
    fn pause_timing_breaks_measurement_chain() {
        let mut tracker = TokenRateTracker::new();
        tracker.start();
        tracker.record(35);
        tracker.pause_timing();
        // After pause, last_timestamp is None
        assert!(tracker.is_streaming()); // streaming flag is not cleared by pause
    }

