    #[test]
    fn apply_provider_usage_overwrites_estimated_tokens() {
        let mut tracker = TokenRateTracker::new();
        tracker.start();
        // Record some chars (estimates tokens internally)
        for _ in 0..20 {
            tracker.record(35);
        }
        // Apply provider usage — should override estimate
        tracker.apply_provider_usage(50);
        // finalize should use provider-corrected tokens
        let entry = tracker.finalize_turn();
        assert_eq!(entry.unwrap().tokens, 50);
    }

    #[test]
    fn apply_provider_usage_accumulates_across_phases() {
        let mut tracker = TokenRateTracker::new();
        tracker.start();
        // Multiple record calls to accumulate inter-token time
        for _ in 0..10 {
            tracker.record(35);
        }
        tracker.apply_provider_usage(30); // first phase
        tracker.apply_provider_usage(20); // second phase
        tracker.apply_provider_usage(10); // third phase (total 60)
        let entry = tracker.finalize_turn();
        // After finalize, session totals should include the 60 tokens
        assert_eq!(entry.unwrap().tokens, 60);
    }

