    #[test]
    fn finalize_turn_uses_minimum_seconds() {
        // Regression: finalize_turn must use seconds.max(0.01) for zero-duration turns
        let mut tracker = TokenRateTracker::new();
        tracker.start();
        tracker.apply_provider_usage(50);
        // No record() calls, so turn_stream_seconds == 0.0
        // finalize_turn should use 0.01 minimum
        let entry = tracker.finalize_turn();
        assert!(entry.is_some());
        let entry = entry.unwrap();
        assert!(entry.seconds >= 0.01);
    }

